SELECT
  'How many sessions for laser hair removal? The honest answer by skin type',
  'how-many-sessions-for-laser-hair-removal',
  'Laser session count varies by skin type, body area, and hair coarseness. A dermatologist breaks down what to expect for Indian Fitzpatrick III-V skin.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The session count for laser hair removal is the most common cost question patients ask before booking. The honest answer depends on three variables: your skin type, the body area, and how coarse your hair is. Here is a dermatologist-level breakdown.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The short answer by body area", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Upper lip / chin — 6 to 10 sessions", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Underarms — 6 to 8 sessions", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Bikini / Brazilian — 6 to 8 sessions", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Full face — 8 to 10 sessions", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Lower legs — 8 to 10 sessions", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 6, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Full legs — 8 to 12 sessions", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 7, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Arms — 8 to 10 sessions", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 8, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Back and chest (men) — 8 to 12 sessions", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Why Indian skin often needs more sessions", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Fitzpatrick III-V skin (most Indian patients) has more melanin in the surrounding tissue, which means we use a slightly lower fluence per session to stay in the safe window. Lower fluence means slower follicle destruction, so a few extra sessions are often needed. The tradeoff is worth it — using unsafe fluence on pigmented skin risks burns, hyperpigmentation, and hypopigmentation.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "By skin type", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Fitzpatrick I-II (fair): 5-7 sessions typical", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Fitzpatrick III (light brown): 6-8 sessions", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Fitzpatrick IV-V (brown to dark brown): 8-10 sessions, often slightly more", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Fitzpatrick VI (very dark): 8-12 sessions, always with a test spot first", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What affects your count", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Three real-world factors:", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Hair colour — dark, coarse hair responds fastest; fine or greying hair needs more sessions", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Hormonal status — PCOS, thyroid disorders, and pregnancy can extend the count", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Consistency — missed or late sessions mean more hairs cycle out of the treatable phase, extending the plan", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Maintenance sessions", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "After the core series, most patients need one maintenance session every 12-24 months to catch newly-active follicles. This is universal — no clinic can promise zero regrowth, forever, without maintenance.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Every laser plan at Uncover starts with an AI skin analysis so your dermatologist can give you a session count based on your actual skin type and hair profile — not a generic quote.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'How Many Sessions for Laser Hair Removal? By Skin Type | Uncover',
  'Dermatologist guide to laser hair removal session counts — face, underarms, legs, bikini — by Fitzpatrick skin type. Honest timelines for Indian patients.',
  218,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'how-many-sessions-for-laser-hair-removal');

DELETE FROM cms.blog_posts_structured_faqs
