INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-many-sessions-for-laser-hair-removal'), 1, 'How many sessions do Indian patients typically need?', 'For Fitzpatrick III-V (most Indians), 6-10 sessions is typical — slightly more than lighter skin types because we use safer, lower fluence settings.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-many-sessions-for-laser-hair-removal'), 2, 'How far apart are the sessions?', 'Face treatments are usually 4 weeks apart; body treatments 4-6 weeks. Spacing matches the hair growth cycle so each session catches follicles in the active phase.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-many-sessions-for-laser-hair-removal'), 3, 'Will I still need maintenance sessions?', 'Yes — most patients need one maintenance session every 12-24 months to catch reactivated follicles. It is not a failure of the treatment, it is how hair biology works.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-many-sessions-for-laser-hair-removal'), 4, 'Why do some clinics promise results in 3 sessions?', 'That is marketing, not medicine. A medically safe laser plan on pigmented Indian skin needs 6+ sessions because of the fluence window. Avoid clinics that guarantee results in fewer.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-many-sessions-for-laser-hair-removal'), 5, 'Can I do fewer sessions if I shave between?', 'Shaving between sessions is recommended and does not reduce session count — the laser targets the follicle bulb under the skin. Plucking, waxing, and threading disrupt the follicle and should be avoided during the treatment series.');

-- ===== is-laser-hair-removal-painful =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'Is laser hair removal painful? What Uncover patients actually say',
  'is-laser-hair-removal-painful',
  'Laser discomfort varies by device, settings, and body area. A dermatologist explains what the sensation actually is, where it hurts most, and how contact-cooling technology changes the experience.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Pain is the second-most-asked question in every laser hair removal consultation (after \"is it permanent\"). The honest answer is: most patients describe the sensation as a mild rubber-band snap or a warm pinch — uncomfortable but tolerable, and shorter than waxing. What makes the biggest difference is the device.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What does laser actually feel like?", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The sensation depends on the wavelength and whether the device uses contact cooling. Modern dermatologist-grade lasers (Alma Soprano Titanium, Candela GentleMax Pro) use a built-in cooling tip that chills the skin to sub-zero temperatures the moment before the pulse fires. Most patients describe the experience as \"warm taps\" rather than \"snaps\".", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Which areas hurt most?", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Upper lip — most sensitive, but sessions are short", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Bikini line and Brazilian — sensitive; comes down a lot by session 3", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Underarms — mild; most patients say it is easier than waxing", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Legs — low, especially lower legs", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Face excluding upper lip — low", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 6, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Chest and back (men) — moderate, mostly from the coarser hair absorbing more laser energy", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "How it compares to waxing and threading", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Most patients who have had both say laser is less painful than a full bikini wax, comparable to or less than threading the upper lip, and noticeably less painful than an epilator. Sessions are also shorter — an upper lip takes 2 minutes of laser versus 5-7 minutes of threading.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What a dermatologist can do to reduce pain", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Numbing cream applied 30 minutes before sensitive-area sessions", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Contact cooling on the handpiece (standard at Uncover)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Fluence titration — start conservative and step up across sessions", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Avoid caffeine on the day of a sensitive-area session", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Book sessions outside the pre-menstrual week when skin sensitivity peaks", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What to expect by session", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Session 1 is the most sensitive because hair is thickest. By session 3-4, most patients report 50-70% less discomfort because the hair is finer and less melanin means less heat absorption. By the end of the series, most patients say it feels like a light warm touch.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'Is Laser Hair Removal Painful? Dermatologist Guide | Uncover',
  'How much does laser hair removal hurt? What contact cooling does, which areas are most sensitive, and what real patients at Uncover say about the sensation.',
  218,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'is-laser-hair-removal-painful');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'is-laser-hair-removal-painful');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'is-laser-hair-removal-painful'), 1, 'Does laser hair removal hurt more than waxing?', 'Most patients say no. Laser has shorter pulses and contact cooling; waxing rips hair out. A full bikini wax is consistently rated more painful than a bikini laser session.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'is-laser-hair-removal-painful'), 2, 'Can I use numbing cream?', 'Yes — for sensitive areas (upper lip, bikini) numbing cream can be applied 30 minutes before the session. Your dermatologist will recommend the right formulation.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'is-laser-hair-removal-painful'), 3, 'Does contact cooling really reduce pain?', 'Yes, significantly. Dermatologist-grade lasers with contact cooling (like Alma Soprano Titanium) chill the skin the moment before each pulse, making the sensation noticeably milder than older IPL-style devices.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'is-laser-hair-removal-painful'), 4, 'Does laser hurt less over time?', 'Yes. As hair thins over the session series, each pulse absorbs less heat. By session 3-4, most patients report significantly less discomfort than session 1.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'is-laser-hair-removal-painful'), 5, 'When is skin most sensitive to laser?', 'The pre-menstrual week (roughly days 21-28 of the cycle). Book sessions outside this window when possible for sensitive areas.');

-- ===== laser-hair-removal-vs-waxing =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'Laser hair removal vs waxing — cost, pain, and 5-year comparison',
  'laser-hair-removal-vs-waxing',
  'Salon waxing and laser have very different cost curves. A dermatologist compares both across 5 years on cost, pain, ingrown hairs, skin damage, and final result.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The laser-versus-waxing comparison is usually framed as a pain debate. The more useful framing is cost and long-term skin health over 5 years. Here is the honest dermatologist view on how they actually stack up.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The 5-year cost comparison", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Assume a typical Indian woman getting underarms and full legs waxed once every 3 weeks at a mid-range salon (₹800 per session). That is ~17 sessions a year, ₹13,600 a year, or ₹68,000 over 5 years. A full laser series for the same areas at Uncover is about ₹60,000-80,000 one-time (8-10 sessions), plus one ₹7,000 maintenance session every 18 months — total ~₹85,000-95,000 over 5 years. After year 5, waxing costs keep going; laser costs drop to just maintenance.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Pain and duration", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Waxing — moderate to high pain, 5-10 minutes per session, monthly forever", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Laser — mild to moderate pain (with contact cooling), 2-5 minutes per area, 6-10 total sessions", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Long-term skin health", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "This is the bigger issue. Repeated waxing over years causes:", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Post-inflammatory hyperpigmentation (dark patches, common on Indian skin)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Ingrown hair scarring on bikini line, neck, underarms", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Folliculitis — inflamed hair follicles", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Thinning skin on frequently waxed areas", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Heightened sensitivity over time", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Laser does the opposite — it reduces hair density over time, so ingrowns taper off and the skin texture generally improves. After a complete laser series, most patients need little to no maintenance shaving between sessions for 6-12 months.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Where waxing still makes sense", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Waxing is still a reasonable choice in three cases: grey or very light hair (laser cannot target without melanin), a single event (wedding, trip, one-off), and temporary budget constraints. For anything regular over months or years, laser wins on cost, pain, and skin health.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "When to consider laser", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Medically, anytime after 16 years of age with stable hormones. Practically, most dermatologists recommend laser if you are already budgeting for monthly waxing — the 2-year ROI is usually clear.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'Laser Hair Removal vs Waxing — 5-Year Cost & Result Compared | Uncover',
  'Laser vs waxing over 5 years: real cost calculation, pain comparison, long-term skin effect, and when waxing still makes sense. An honest dermatologist view.',
  218,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'laser-hair-removal-vs-waxing');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-vs-waxing');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-vs-waxing'), 1, 'Is laser cheaper than waxing long-term?', 'By year 3-4 for most patients, laser breaks even and then becomes cheaper. By year 10 the savings are substantial.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-vs-waxing'), 2, 'Can I switch from waxing to laser?', 'Yes. Most dermatologists ask for a 2-4 week wax-free gap before starting laser, because the laser needs the hair in the follicle to target.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-vs-waxing'), 3, 'Does waxing damage skin?', 'Repeated waxing over years does — post-inflammatory pigmentation, ingrowns, folliculitis, and thinning skin are all documented long-term effects.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-vs-waxing'), 4, 'When should I not pick laser?', 'If your hair is grey, if you are pregnant (we pause laser for the duration), or if you have active skin infection in the target area.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-vs-waxing'), 5, 'Does laser permanently replace waxing?', 'For most patients, yes — a complete laser series reduces hair 70-90% permanently. You switch from monthly waxing to one maintenance laser session every 12-24 months.');

-- ===== laser-hair-removal-before-and-after =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'Laser hair removal before and after — what realistic results look like',
  'laser-hair-removal-before-and-after',
  'What to actually expect at each stage of a laser hair removal series — session 1, session 4, end of series, and 2 years later. A dermatologist''s realistic timeline.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Before-and-after laser photos on social media tend to be curated to the most dramatic cases. The realistic timeline — what most patients actually see — is less Instagram-ready but more useful to plan from.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Session 1 — what happens and what you see", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Session 1 is the first time your follicles absorb laser energy. The laser destroys a percentage of active follicles outright and damages many more. Right after the session, you will notice small red bumps at the follicle openings for a few hours. Over the next 10-14 days, treated hair works its way out of the follicle and falls off on its own when you shower. By day 14-21 the treated area feels mostly smooth, and new hair starts appearing at day 28-30 from follicles that were dormant during your session.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Session 4 — the midpoint", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "By session 4 (roughly 3-4 months in), most patients report 40-60% less density. Regrowth is slower, finer, and patchier — the first obvious visual win. Ingrowns and razor bumps usually stop appearing by this point.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "End of series (session 8-10) — the main result", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "After the complete series, most patients land at 70-90% hair reduction. What this looks like: the area stays smooth for weeks without shaving, a few fine hairs persist and are easy to manage, and coarse thick hair is effectively gone. This is the stable outcome most dermatologists consider \"permanent reduction\".", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Year 2 — maintenance", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Around the 12-18 month mark, a small percentage of dormant follicles reactivate. Most patients notice a few new hairs and book one maintenance session to catch them. This single session is usually enough to reset the density for another 1-2 years.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Year 5 — long-term", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Most patients who completed a full series and did 1-2 maintenance sessions still have 80%+ hair reduction at year 5. The remaining hair is fine and cosmetically invisible.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What affects your personal result", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Skin type — darker skin needs a longer series but reaches the same end point", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Hair colour — grey or white hair responds poorly; very dark hair responds best", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Hormonal status — PCOS, thyroid, pregnancy can extend the timeline", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Device — dermatologist-grade lasers outperform salon IPL by 2-3x", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Compliance — missed or late sessions reduce the final result", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "At Uncover we document before/after photos at each session with standardised lighting so you can see your own timeline objectively, not just the best angle.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'Laser Hair Removal Before and After — Realistic Timeline | Uncover',
  'What real laser hair removal results look like by session — 1, 4, 8, and 2 years out. A dermatologist''s timeline for Indian skin, without marketing inflation.',
  218,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'laser-hair-removal-before-and-after');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-before-and-after');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-before-and-after'), 1, 'When will I see results?', 'Meaningful visual reduction by session 3-4. The primary result is at the end of the full series (session 8-10).'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-before-and-after'), 2, 'Is session 1 immediately visible?', 'Not usually. Treated hair sheds over 10-14 days, and dormant follicles start regrowing by day 28. The first session dilates results more than it removes density.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-before-and-after'), 3, 'How long do results last?', '70-90% reduction after the full series is stable for years with one maintenance session every 12-24 months.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-before-and-after'), 4, 'Will I see patchy regrowth?', 'Some patchiness is normal across sessions — follicles cycle through growth phases and not every follicle is caught in every session. By session 6-8 the patches flatten.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'laser-hair-removal-before-and-after'), 5, 'Can I stop the series early and still get results?', 'Stopping early (session 4-5) gives you maybe 50% reduction and most of that fades within 12 months. A full series is what produces stable, long-term results.');

-- ===== is-botox-safe =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'Is botox safe? A dermatologist''s honest guide',
  'is-botox-safe',
  'Botox is one of the most studied drugs in dermatology. A dermatologist explains what the safety data actually says, what side effects to expect, and when to say no.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Botox has one of the strongest safety records in cosmetic dermatology — it has been studied clinically for over 30 years and used for cosmetic purposes for over 20. The short answer is: botox is safe when administered by a board-certified dermatologist in correct doses. The longer answer is about knowing what can go wrong and how to avoid it.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What botox actually is", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Botox is a purified form of botulinum toxin type A. At cosmetic doses it temporarily blocks the nerve signal to specific muscles, relaxing them for 3-6 months. The dose used for cosmetic treatment is approximately 1% of the dose that would cause systemic symptoms, with a wide therapeutic margin.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What the safety data shows", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Clinical studies covering millions of treatments show the most common side effects are local and temporary — mild bruising at the injection site, minor headache in the first 24 hours, and occasional droopy eyelid (ptosis) if injected too near the levator muscle. Serious adverse events are rare and almost always linked to counterfeit product or unqualified injectors.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Who should avoid botox", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Pregnancy and breastfeeding (precautionary, no evidence of harm)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Myasthenia gravis and other neuromuscular disorders", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Known allergy to botulinum toxin or albumin", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Active skin infection at the planned injection site", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Patients on aminoglycoside antibiotics (can amplify the effect)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Red flags for unsafe botox", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Most safety problems come from unqualified injectors, not the drug itself. Avoid:", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Non-medical providers (spas, salons, hairdressers offering botox)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Prices that seem too good — counterfeit or diluted product is a major risk in India", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "No consent form or pre-treatment photography", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "No discussion of your medical history or medications", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Injection at your first appointment without any assessment", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What to expect after a safe treatment", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Mild swelling and small red dots at injection points for 10-20 minutes. Avoid lying flat, vigorous exercise, saunas, and facial massage for 24 hours. Results start at day 3, peak at day 14. Book a review at 2 weeks if you want to add more — it is always better to add than to try to remove.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "At Uncover, every botox treatment is performed by a board-certified dermatologist, uses only US-FDA approved product (Allergan, Galderma, or equivalent), and includes a full medical history review before the first injection.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'Is Botox Safe? Dermatologist Honest Safety Guide | Uncover',
  'Dermatologist-led guide to botox safety — what the clinical evidence says, what real side effects to expect, who should avoid botox, and how to choose a safe provider.',
  216,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'is-botox-safe');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'is-botox-safe');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'is-botox-safe'), 1, 'Is botox a poison?', 'Yes, in very high doses. At cosmetic doses (under 100 units per session typically) it has an excellent safety profile with a wide therapeutic margin.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'is-botox-safe'), 2, 'Can botox travel to other parts of the body?', 'At cosmetic doses, no. The product stays localised in the muscle where it is injected.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'is-botox-safe'), 3, 'Can I have botox if I am breastfeeding?', 'We recommend waiting. There is no evidence of harm but the FDA precautionary guidance is to avoid it during pregnancy and breastfeeding.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'is-botox-safe'), 4, 'What is the main safety risk?', 'Unqualified injectors using counterfeit or diluted product. The drug itself has an excellent safety record — the risk is almost always the provider.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'is-botox-safe'), 5, 'Is botox safe to repeat for decades?', 'Yes. Many patients have received botox for 15-20 years without adverse effects. Long-term users often need fewer units per session because muscles retrain to relax.');

-- ===== how-to-get-clear-skin-naturally =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'How to get clear skin naturally — an Indian dermatologist''s guide',
  'how-to-get-clear-skin-naturally',
  'Real, evidence-based habits that improve skin clarity — and when home remedies stop working and you need professional help. Written for Indian skin.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "\"Clear skin naturally\" searches bring up thousands of miracle recipes. Most do not work. A dermatologist-backed approach is less exciting but more effective — build a simple routine, address the root cause, and know when to escalate.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The five non-negotiables", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Sunscreen SPF 50 every morning, 365 days a year, indoors and out", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "A gentle sulphate-free cleanser twice a day", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "A niacinamide or vitamin C serum in the morning", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "A retinoid 2-3 nights per week (stepping up gradually)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Moisturiser at night to support the skin barrier", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "If you do those five things consistently for 3 months, most skin improves visibly. That is the baseline — everything else is targeted work.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Diet and lifestyle — what actually helps", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Reduce dairy and high-glycemic foods if acne is persistent", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Sleep 7-8 hours — skin repair happens overnight", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Hydrate — 2-3 litres daily improves surface hydration", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Manage stress — cortisol worsens acne, eczema, and rosacea", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Limit ultra-processed foods, excess sugar, and alcohol", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What does not work", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Honest list: lemon juice (damages the skin barrier, can cause phytodermatitis burns), toothpaste on pimples (irritating chemicals), excessive exfoliation (strips the barrier), homemade ubtan for pigmentation (usually worsens it), and scrubbing your face harder. None of these fix the underlying problem.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "When to see a dermatologist", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Acne that leaves dark marks or scars", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Pigmentation that does not fade over 3 months", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Persistent redness or visible capillaries", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Cystic acne (deep painful bumps)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Melasma, especially if it is spreading", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 6, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Any skin change you cannot explain — growths, mole changes, lasting rash", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Clear skin is a compounding result — daily basics plus professional assessment at the 3-month mark if the routine is not moving the needle. At Uncover every visit starts with an AI skin analysis so you can see what is actually changing, beyond the mirror.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'How to Get Clear Skin Naturally — Indian Dermatologist Guide | Uncover',
  'A dermatologist-led guide to getting clear skin naturally — daily habits, what actually works for Indian skin, and the signs it is time to see a professional.',
  216,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'how-to-get-clear-skin-naturally');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-get-clear-skin-naturally');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-get-clear-skin-naturally'), 1, 'Can clear skin really be achieved naturally?', 'Yes for maintenance and mild conditions. For acne scarring, stubborn pigmentation, rosacea, or cystic acne, "natural" is not enough — professional treatment is needed.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-get-clear-skin-naturally'), 2, 'Which home remedy actually works?', 'Most do not. Green tea compresses and aloe vera are mildly soothing; honey is a mild antibacterial. None of these replace proper skincare basics.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-get-clear-skin-naturally'), 3, 'How long does it take to see clear skin?', 'With a consistent basic routine, most skin shows visible improvement in 6-12 weeks. Full turnover of a layer of skin is 28 days — meaningful change requires at least 3 cycles.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-get-clear-skin-naturally'), 4, 'Does diet affect skin?', 'Yes for some patients. Dairy and high-glycemic foods are the two most-studied acne triggers. Other effects vary by person.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-get-clear-skin-naturally'), 5, 'When should I see a dermatologist?', 'If 3 months of a basic routine has not helped, if you have scarring, if pigmentation is spreading, or if you are treating anything with prescription topicals without medical supervision.');

-- ===== how-to-reduce-acne-scars-naturally =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'How to reduce acne scars naturally — and when home remedies stop working',
  'how-to-reduce-acne-scars-naturally',
  'Home treatments can help fade early post-acne marks but cannot treat true textural scarring. A dermatologist explains the difference and when to escalate.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Most patients who search for \"reduce acne scars naturally\" are actually dealing with post-acne marks (flat dark spots), not true textural scars. The two respond very differently. Here is how to tell them apart and what to realistically expect.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Post-inflammatory hyperpigmentation vs true scars", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Post-inflammatory hyperpigmentation (PIH) is the flat brown or red mark left after an acne lesion heals. It is pigment change, not texture. PIH fades over 6-12 months on its own and can be accelerated with at-home skincare. True acne scars are textural — ice pick, boxcar, rolling — and will not fade naturally no matter how long you wait.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What works for PIH at home", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Daily SPF 50 — sun exposure is what keeps PIH dark", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Niacinamide serum (5-10%) — brightens and evens tone", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Vitamin C serum in the morning — inhibits melanin production", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Azelaic acid 10-15% — gentle brightener, safe for Indian skin", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Retinoid 2-3 nights per week — accelerates cell turnover", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 6, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Gentle chemical exfoliation with mandelic or lactic acid 1-2 nights per week", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Consistent use for 3-6 months usually lightens PIH significantly. The slowest factor is skin cell turnover — patience is required.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What does not work for true scars", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Lemon juice, rice water, tomato pulp, Ayurvedic ubtan, and most Pinterest remedies do nothing for textural scars. Some actively damage the skin barrier. Dermabrasion at home (walnut scrubs, apricot scrubs) can deepen scarring.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "When home treatment stops working", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "If after 3 months of consistent use you have not seen meaningful progress, or if your issue is textural (pits, bumps, rolling shadows), you have crossed the home-remedy ceiling. True scars need professional treatment — fractional CO2 laser, subcision, TCA CROSS for ice pick scars, RF microneedling. At Uncover acne scar treatments start at ₹10,999 for microneedling and scale up based on scar type.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The realistic expectation", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Home treatment fades PIH 40-70% over 6 months. Professional treatment for true scars reduces them 60-80% over 4-6 sessions. Severe pitted scars rarely go to 100%, but they can be smoothed enough to be cosmetically invisible.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Every scar assessment at Uncover begins with an AI skin analysis that identifies scar type (ice pick, boxcar, rolling) alongside any PIH, so the plan targets both accurately.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'How to Reduce Acne Scars Naturally — What Works, When to Escalate | Uncover',
  'Natural ways to fade post-acne marks vs true scars. A dermatologist explains what home remedies can do, what they cannot, and the escalation path for real results.',
  216,
  false, 'published', now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'how-to-reduce-acne-scars-naturally');

DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-reduce-acne-scars-naturally');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-reduce-acne-scars-naturally'), 1, 'Can acne scars be removed naturally?', 'Post-acne dark marks (PIH) — yes, with sunscreen and brightening serums over 6 months. True textural scars — no, they need professional treatment.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-reduce-acne-scars-naturally'), 2, 'Does lemon juice lighten scars?', 'No. It is phototoxic and can cause burns and worsen pigmentation on Indian skin. Skip it.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-reduce-acne-scars-naturally'), 3, 'How long does PIH take to fade naturally?', '6-12 months on its own. With a consistent routine of SPF, niacinamide, vitamin C, and a retinoid, usually 3-6 months.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-reduce-acne-scars-naturally'), 4, 'What is the best professional treatment for acne scars?', 'For Indian skin: RF microneedling, subcision, TCA CROSS for ice pick scars, fractional CO2 at conservative settings. The right mix is based on your scar types.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-reduce-acne-scars-naturally'), 5, 'When should I see a dermatologist for acne scars?', 'If your scars are textural, if 3 months of topicals has not helped PIH, or if acne is still active (we need to stabilise active breakouts before treating scars).');

COMMIT;
